mapper.select:
select e.emp_id as EMP_ID, e.dept_id as DEPT_ID, e.position_id as POSITION_ID, e.password as PASSWORD, e.name as NAME, e.email as EMAIL, e.phone as PHONE, e.status_code as STATUS_CODE, e.login_fail_cnt as LOGIN_FAIL_CNT, e.hire_date as HIRE_DATE, e.is_deleted as IS_DELETED, e.version as VERSION, e.created_at as CREATED_AT, e.created_by as CREATED_BY, e.updated_at as UPDATED_AT, e.updated_by as UPDATED_BY from employees_51 e where e.is_deleted = 'n'
and e.name like '%' + #{searchName} + '%'
and e.dept_id = #{searchDeptId}
and e.status_code = #{searchStatus}
order by e.emp_id asc

select e.emp_id as EMP_ID, e.dept_id as DEPT_ID, e.position_id as POSITION_ID, e.name as NAME, e.email as EMAIL, e.phone as PHONE, e.status_code as STATUS_CODE, e.login_fail_cnt as LOGIN_FAIL_CNT, e.hire_date as HIRE_DATE, e.is_deleted as IS_DELETED, e.version as VERSION, e.created_at as CREATED_AT, e.created_by as CREATED_BY, e.updated_at as UPDATED_AT, e.updated_by as UPDATED_BY, d.dept_name as DEPT_NAME, p.position_name as POSITION_NAME from employees_51 e left join departments_51 d on e.dept_id = d.dept_id and d.is_deleted = 'n' left join positions_51 p on e.position_id = p.position_id and p.is_deleted = 'n' where e.is_deleted = 'n'
and e.name like '%' + #{searchName} + '%'
and e.dept_id = #{searchDeptId}
and e.status_code = #{searchStatus}
order by e.emp_id asc offset #{offset} rows fetch next #{pageSize} rows only

select count(*)
from employees_51 e
where e.is_deleted = 'n'

    and e.name like '%' + #{searchName} + '%'


