update employees_51
set is_deleted = 'y',
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where emp_id   = #{empId}
  and is_deleted = 'n'

update employees_51
set status_code = #{statusCode},
    updated_at  = #{updatedAt},
    updated_by  = #{updatedBy}
where emp_id    = #{empId}
  and is_deleted = 'n'
